// PHASE C RECONCILIATION PREVIEW — Read-only classification
// Source of truth: Sent Log. OQ is rebuilt from Sent Log truth in Phase E.

const HOLD_OPP_IDS = new Set([
  '4487ac861d0a', 'd0eff2075a84', 'f680494b6b8f', 'be2b65c90332'
]);
const STALE_DAYS = 14;
const FOLLOWUP_LAG_BUSINESS_DAYS = 3;
const HELD_SUPPRESSION_DAYS = 90;

const oqRows       = $('Read Outreach Queue').all().map(i => i.json);
const sentRows     = $('Read Sent Log').all().map(i => i.json);
const excludedRows = $('Read Excluded Companies').all().map(i => i.json);
const trackerRows  = $('Read Sequence Tracker').all().map(i => i.json);

// Excluded company names (lowercased). Substring match against company_name (WF1 convention).
const excludedNames = excludedRows
  .map(r => (r.company_name || '').toLowerCase().trim())
  .filter(Boolean);

// Build email -> [sent_timestamp] map from Sent Log
const sentByEmail = new Map();
for (const r of sentRows) {
  const email = (r.contact_email || '').toLowerCase().trim();
  if (!email) continue;
  const ts = r.sent_timestamp ? new Date(r.sent_timestamp) : null;
  if (!ts || isNaN(ts.getTime())) continue;
  if (!sentByEmail.has(email)) sentByEmail.set(email, []);
  sentByEmail.get(email).push(ts);
}
for (const arr of sentByEmail.values()) arr.sort((a, b) => a - b);

const today = new Date();
const addBusinessDays = (d, n) => {
  const r = new Date(d);
  let added = 0;
  while (added < n) {
    r.setDate(r.getDate() + 1);
    const dow = r.getDay();
    if (dow !== 0 && dow !== 6) added++;
  }
  return r.toISOString().split('T')[0];
};

// Filter OQ to non-rejected
const oqNonReject = oqRows.filter(r => {
  const s = (r.approval_status || '').toLowerCase().trim();
  return s !== 'reject' && s !== 'rejected';
});

const buckets = {
  excluded_archive: [],
  held_campaign_overlap: [],
  warm_complete_migrate_cold: [],
  mid_sequence_reconcile: [],
  fresh_keep: []
};

const midRecency = { '<=7': 0, '8-14': 0, '15-30': 0, '30+': 0 };

for (const row of oqNonReject) {
  const email = (row.contact_email || '').toLowerCase().trim();
  const companyLower = (row.company_name || '').toLowerCase().trim();
  const oppId = (row.opportunity_id || '').trim();

  const sends = sentByEmail.get(email) || [];
  const sendCount = sends.length;
  const lastSent = sends.length ? sends[sends.length - 1] : null;
  const daysSinceLast = lastSent ? Math.floor((today - lastSent) / 86400000) : null;

  // Rule 1: Excluded company (substring match)
  const excludedMatch = companyLower
    ? excludedNames.find(n => n && companyLower.includes(n))
    : null;
  if (excludedMatch) {
    buckets.excluded_archive.push({
      ...row,
      _send_count: sendCount,
      _last_sent_date: lastSent ? lastSent.toISOString() : null,
      _days_since_last_sent: daysSinceLast,
      _excluded_match: excludedMatch,
      _archive_reason: 'excluded_company'
    });
    continue;
  }

  // Rule 2: HOLD list — campaign overlap
  if (HOLD_OPP_IDS.has(oppId)) {
    buckets.held_campaign_overlap.push({
      ...row,
      _send_count: sendCount,
      _last_sent_date: lastSent ? lastSent.toISOString() : null,
      _days_since_last_sent: daysSinceLast,
      _new_approval_status: 'held_campaign_overlap',
      _add_to_suppression_until: new Date(today.getTime() + HELD_SUPPRESSION_DAYS * 86400000).toISOString().split('T')[0]
    });
    continue;
  }

  // Rule 3: 3+ warm sends → complete, migrate to cold
  if (sendCount >= 3) {
    buckets.warm_complete_migrate_cold.push({
      ...row,
      _send_count: sendCount,
      _last_sent_date: lastSent ? lastSent.toISOString() : null,
      _days_since_last_sent: daysSinceLast,
      _archive_reason: 'migrated_cold',
      _cold_industry: 'Other',
      _cold_needs_classification: 'TRUE'
    });
    continue;
  }

  // Rule 4: 1-2 warm sends → mid_sequence_reconcile
  if (sendCount >= 1 && sendCount <= 2) {
    let recencyBand;
    if (daysSinceLast <= 7) recencyBand = '<=7';
    else if (daysSinceLast <= 14) recencyBand = '8-14';
    else if (daysSinceLast <= 30) recencyBand = '15-30';
    else recencyBand = '30+';
    midRecency[recencyBand]++;

    const isStale = daysSinceLast > STALE_DAYS;
    const nextStage = sendCount; // 0-indexed prior stage done

    const update = isStale
      ? {
          _action: 'hold_manual_review',
          _new_approval_status: 'pending',
          _new_sent_status: 'unsent',
          _new_follow_up_stage: nextStage,
          _new_scheduled_date: '',
          _stale: true
        }
      : {
          _action: 'reschedule_next_stage',
          _new_approval_status: 'approved',
          _new_sent_status: 'unsent',
          _new_follow_up_stage: nextStage,
          _new_scheduled_date: addBusinessDays(today, FOLLOWUP_LAG_BUSINESS_DAYS),
          _stale: false
        };

    buckets.mid_sequence_reconcile.push({
      ...row,
      _send_count: sendCount,
      _last_sent_date: lastSent ? lastSent.toISOString() : null,
      _days_since_last_sent: daysSinceLast,
      _recency_band: recencyBand,
      ...update
    });
    continue;
  }

  // Rule 5: 0 warm sends → fresh_keep
  buckets.fresh_keep.push({
    ...row,
    _send_count: sendCount,
    _last_sent_date: null,
    _days_since_last_sent: null
  });
}

// Dedup check vs Sequence Tracker (cold sheet) — case-insensitive Email match
const trackerEmailSet = new Set(
  trackerRows
    .map(r => (r.Email || '').toLowerCase().trim())
    .filter(Boolean)
);
const warmCompleteEmails = buckets.warm_complete_migrate_cold
  .map(r => (r.contact_email || '').toLowerCase().trim())
  .filter(Boolean);
const alreadyInColdList = warmCompleteEmails.filter(e => trackerEmailSet.has(e));
const dedup_check = {
  warm_complete_count: warmCompleteEmails.length,
  sequence_tracker_unique_emails: trackerEmailSet.size,
  already_in_cold: alreadyInColdList.length,
  net_new_to_migrate: warmCompleteEmails.length - alreadyInColdList.length,
  already_in_cold_emails: alreadyInColdList
};

// Safety assertion: totals must reconcile
const totalClassified = Object.values(buckets).reduce((s, arr) => s + arr.length, 0);
const assertion = {
  total_classified: totalClassified,
  oq_non_reject_count: oqNonReject.length,
  pass: totalClassified === oqNonReject.length
};
if (!assertion.pass) {
  throw new Error(`Safety assertion FAILED: classified ${totalClassified} != non-reject OQ ${oqNonReject.length}`);
}

// Mid-sequence before/after samples
const midBeforeAfter = buckets.mid_sequence_reconcile.slice(0, 5).map(r => ({
  opportunity_id: r.opportunity_id,
  contact_email: r.contact_email,
  company_name: r.company_name,
  current_row: {
    approval_status: r.approval_status,
    sent_status: r.sent_status,
    follow_up_stage: r.follow_up_stage,
    scheduled_date: r.scheduled_date
  },
  computed: {
    send_count: r._send_count,
    last_sent_date: r._last_sent_date,
    days_since_last_sent: r._days_since_last_sent,
    recency_band: r._recency_band,
    stale: r._stale
  },
  proposed_update: {
    action: r._action,
    approval_status: r._new_approval_status,
    sent_status: r._new_sent_status,
    follow_up_stage: r._new_follow_up_stage,
    scheduled_date: r._new_scheduled_date
  }
}));

// Lightweight sample for the other 4 buckets
const sample = (arr, n) => arr.slice(0, n).map(r => {
  const out = {
    opportunity_id: r.opportunity_id,
    contact_email: r.contact_email,
    company_name: r.company_name,
    send_count: r._send_count,
    last_sent_date: r._last_sent_date,
    days_since_last_sent: r._days_since_last_sent
  };
  if (r._excluded_match) out.excluded_match = r._excluded_match;
  if (r._archive_reason) out.archive_reason = r._archive_reason;
  if (r._new_approval_status) out.new_approval_status = r._new_approval_status;
  if (r._add_to_suppression_until) out.add_to_suppression_until = r._add_to_suppression_until;
  return out;
});

return [{
  json: {
    phase: 'C — preview only, no writes',
    inputs: {
      outreach_queue_total: oqRows.length,
      outreach_queue_non_reject: oqNonReject.length,
      sent_log_total: sentRows.length,
      excluded_companies_total: excludedRows.length,
      sequence_tracker_total: trackerRows.length
    },
    bucket_counts: {
      excluded_archive: buckets.excluded_archive.length,
      held_campaign_overlap: buckets.held_campaign_overlap.length,
      warm_complete_migrate_cold: buckets.warm_complete_migrate_cold.length,
      mid_sequence_reconcile: buckets.mid_sequence_reconcile.length,
      fresh_keep: buckets.fresh_keep.length
    },
    mid_sequence_recency: midRecency,
    dedup_check,
    samples: {
      excluded_archive: sample(buckets.excluded_archive, 5),
      held_campaign_overlap: sample(buckets.held_campaign_overlap, 5),
      warm_complete_migrate_cold: sample(buckets.warm_complete_migrate_cold, 5),
      mid_sequence_reconcile: sample(buckets.mid_sequence_reconcile, 5),
      fresh_keep: sample(buckets.fresh_keep, 5)
    },
    mid_sequence_before_after: midBeforeAfter,
    assertion
  }
}];
